INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1001, 0, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 2, "お！\nあそこに困ってそうな人発見！", 1, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 0, "春咲 ひより", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1002, 0, "みんなみたいに\nわたしも強くならなきゃ", 1, 2, "大切な人を\n守れるようになりたい…って", 1, "わ、わたし、\nなに言ってるんだろ\nあはは…", 0, "草野 優衣", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1003, 0, "フェンシングを始めてみては？", 1, 2, "キミに必要な集中力と感性が", 1, "少しは磨かれると思いますよ。", 0, "士条 怜", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1004, 0, "ねぇ、にいちゃん！", 1, 2, "今日はなにして遊ぶ？", 1, "みそぎはねぇ、\nかくれんぼやりたい！", 0, "穂高 みそぎ", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1006, 0, "風宮あかりです", 1, 2, "ねぇ…", 1, "私といっしょに…\nいかない？", 0, "風宮 あかり", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1007, 0, "出雲宮子なのー", 1, 2, "プリンたべたいのー", 1, "食べ物の恨みは怖いのー", 0, "出雲 宮子", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1008, 0, "ボクは虹村雪。", 1, 2, "キミもボクの美貌に\n吸い寄せられたんだね。", 1, "いいよ。\n見られることは運命さ…", 0, "虹村 雪", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1009, 0, "フッ…聞いて後悔するがいい！", 1, 2, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1, "人呼んで「疾風の冥姫」!!", 0, "柊杏奈", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1010, 0, "マホマホ王国のプリンセス、\nまほ姫どす", 1, 2, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1, "ほんまおおきにやわ～♪", 0, "姫宮 真歩", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1011, 0, "衣之咲璃乃です！", 1, 2, "生き別れたお兄ちゃんを探して\n三千世界！", 1, "ここで会ったが\n100年目～！", 0, "衣之咲 璃乃", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1012, 0, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 2, "ち、超能力って…\n何のことかな～？", 1, "…って、お願い！\n誰にも言わないでおいて～！", 0, "柏崎 初音", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1016, 0, "ちょす！\n美波鈴奈だよ～♪", 1, 2, "一応カリスマ読モJKやってまっす！", 1, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 0, "美波 鈴奈", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1017, 0, "はいたーい。\n喜屋武香織さー。", 1, 2, "東京は遊園地みたいなところさー", 1, "でも、沖縄もとってもいいとこさー", 0, "喜屋武 香織", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1018, 0, "支倉伊緒です。", 1, 2, "先生って呼ばれるのは\nくすぐったいから", 1, "イオちゃんって呼んでね。", 0, "支倉 伊緒", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1020, 0, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 2, "あ！/\お兄ちゃ～ん\nまってよ～", 1, "ミミをおいてかないでぇ～", 0, "茜 ミミ", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1021, 0, "あ…あの…えっと…\n栗…林…くるみ…です……", 1, 2, "あの……\nふぇ……", 1, "ふぇぇぇぇぇん……", 0, "栗林 くるみ", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1022, 0, "風宮よりです。\nあああああ！", 1, 2, "こんな私に貴重な時間を\n割いていただき、", 1, "なんてありがとうございます！", 0, "風宮 より", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1023, 0, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 2, "おにいちゃんどこいくの？\nえ？", 1, "私こっち行きたいー\nね、早く早くー", 0, "北条 綾音", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1025, 0, "わっ…わっ…私、\n天野すずめといいます！", 1, 2, "ふ、不束者ですが\nどうぞ末永く…って、", 1, "これて何か違う…\nあああすみません！", 0, "天野 すずめ", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1027, 0, "……クスクス…私は\n…倉石恵理子……", 1, 2, "あなたは…運命の……\n伴侶……", 1, "離しませんわ………\n絶対に…!!", 0, "倉石 恵理子", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1028, 0, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 2, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1, "…そうでしょ？？", 0, "佐々木 咲恋", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1029, 0, "桜井望だよ！\nよろしくねっ", 1, 2, "ぇっと…\nキミ、私のこと知らないの?!", 1, "あはは、\n私もまだまだだなぁ～", 0, "桜井 望", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1030, 0, "デケデケデンっ！", 1, 2, "初めまして、\n私はニノン・ジュベール申すデス！", 1, "ショーグン、\nワタシと一緒に天下統一デース！", 0, "ニノン・ジュベール", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1031, 0, "上喜しのぶです。\n手元のドクロが父です。", 1, 2, "でもって私の隣にいるのが……\nえ、見えない？", 1, "おかしいですね……", 0, "上喜 しのぶ", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1033, 0, "目指すはビッグな\nお笑い芸人だっぺ！", 1, 2, "けんども\nそれには足りないモンが…", 1, "そう、\nオラのボケに突っ込める相方が…！", 0, "野戸まひる", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1034, 0, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 2, "ちょっと緊張しちゃって…", 1, "ちょ\nちょっと一杯飲んできます…！", 0, "綾瀬 ゆかり", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1036, 0, "氷川鏡華…です", 1, 2, "知らない人とは話しちゃいけないので", 1, "これ以上お話しすることは…\nないです！", 0, "氷川 鏡華", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1038, 0, "柏崎…栞です。", 1, 2, "……あ、アラーム。", 1, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 0, "柏崎 栞", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1040, 0, "ふ、双葉碧です。", 1, 2, "私、一人も友達がいなくて……", 1, "野に咲く花が、\n唯一の話相手です。", 0, "双葉 碧", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1042, 0, "三角千歌です。", 1, 2, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1, "そう思っています。", 0, "三角 千歌", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1043, 0, "安芸真琴だ。", 1, 2, "あぁ？\nお前のそいつの仲間か？", 1, "う、疑ってすまなかったな…", 0, "安芸 真琴", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1044, 0, "わらわこそは夜を総べる者！", 1, 2, "生けとし生ける全ての者よ！", 1, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 0, "イリヤ・オーンスタイン", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1045, 0, "そこで騎士は妖精を乱暴に……", 1, 2, "ぐふふふふ……はっ！", 1, "ｌク、クウカに何かご用ですか!?", 0, "遠見 空花", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1046, 0, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 2, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1, "う～ん…\n猫ってホントに最高にゃ～♪", 0, "宮坂たまき", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1048, 0, "大神美冬よ！", 1, 2, "それでは早速クエストに…", 1, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 0, "大神 美冬", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1049, 0, "星野静流だよ！", 1, 2, "クエストもバトルも\n掃除も洗濯も", 1, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 0, "星野静流", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1050, 0, "アタシは玉泉美咲。", 1, 2, "見ての通りの\nセクシー美少女で", 1, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 0, "玉泉美咲", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1052, 0, "？？？", 1, 2, "？？？？", 1, "？？？？", 0, "リマ", 0, 1.4, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1053, 0, "モニカ・ヴァイスヴィントだ。", 1, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "そ、そこまでいうなら\nもらってやる", 0, "モニカ・ヴァイスヴィント", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1058, 0, "モニカ・ヴァイスヴィントだ。", 1, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "そ、そこまでいうなら\nもらってやる", 0, "ペコリーヌ", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1059, 0, "モニカ・ヴァイスヴィントだ。", 1, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "そ、そこまでいうなら\nもらってやる", 0, "コッコロ", 0, 1.5, 0, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1060, 0, "モニカ・ヴァイスヴィントだ。", 1, 2, "菓子でつろうなどと\n稚拙な策を……", 1, "そ、そこまでいうなら\nもらってやる", 0, "キャル", 0, 1.5, 0, 0, 1);
